-- Menu Player Career ---- SelectFormation Remode By Septiawan --local SelectFormation = {}local BND_LIST      = "bnd_list"local BND_INDEX     = "bnd_index"local BND_WIDTH     = "bnd_width"local BND_HEIGHT    = "bnd_height"local BND_ITEM_TYPE = "bnd_item_type"local ACT_CHANGE = "act_change"local ACT_SELECT = "act_select"local ACT_CLOSE  = "act_close"function SelectFormation:new(init)  local o = init or {}  setmetatable(o, self)  self.__index = self  o.currentIndex = nil  o.im.Subscribe(BND_LIST, function()    o.im.Publish(BND_LIST, o.data.tableData)    if o.currentIndex == nil       and o.data.tableData       and #o.data.tableData > 0 then      o.currentIndex = 0    end  end)  o.im.Subscribe(BND_WIDTH, function()    o.im.Publish(BND_WIDTH, o.data.width)  end)  o.im.Subscribe(BND_HEIGHT, function()    o.im.Publish(BND_HEIGHT, o.data.height)  end)  o.im.Subscribe(BND_ITEM_TYPE, function()    o.im.Publish(BND_ITEM_TYPE, o.data.itemType)  end)  o.im.RegisterDataAction(BND_INDEX, ACT_CHANGE,    function(_, _, index)      o.currentIndex = index    end  )  o.im.RegisterAction(ACT_SELECT,    function()      if o.currentIndex == nil then        return      end      o.data.callBack({        index = o.currentIndex      })      o.nav.Event(nil, "evt_hide_overlay")    end  )    o.im.RegisterAction(ACT_CLOSE,    function()      o.data.callBack({ canceled = true })      o.nav.Event(nil, "evt_hide_overlay")    end  )  return oendfunction SelectFormation:finalize()  self.im.Unsubscribe(BND_LIST)  self.im.Unsubscribe(BND_WIDTH)  self.im.Unsubscribe(BND_HEIGHT)  self.im.Unsubscribe(BND_ITEM_TYPE)  self.im.UnregisterDataAction(BND_INDEX, ACT_CHANGE)  self.im.UnregisterAction(ACT_SELECT)  self.im.UnregisterAction(ACT_CLOSE)endreturn SelectFormation